The puzzle known as N queens is a problem that involves placing N chess queens on an N×N chessboard such that no two queens are capable of threatening each other. This means that a valid solution must ensure that no two queens are positioned on the same row, column, or diagonal of the board.

```
// C# code to for n Queen placement
using System;

class GfG
{
    static void breakLine()
    {
        Console.Write("\n---------------------------------\n");
    }

    // maximum size of the chessboard
    static int MAX = 10;

    // array to store queen placements
    static int[] arr = new int[MAX];

    // variable to count the number of solutions found
    static int no;

    // recursive function to find solutions
    static void nQueens(int k, int n)
    {
        // try all possible positions for queen in the current row
        for (int i = 1; i <= n; i++)
        {
            // check if queen can be placed at the current position
            if (canPlace(k, i))
            {
                // place the queen at the current position
                arr[k] = i;

                // if all queens are placed, display the solution
                if (k == n)
                {
                    display(n);
                }
                else
                {
                    // recursively try to place remaining queens
                    nQueens(k + 1, n);
                }
            }
        }
    }

    // helper function to check if queen can be placed at the current position
    static bool canPlace(int k, int i)
    {
        for (int j = 1; j <= k - 1; j++)
        {
            // check if queen is already placed in the same column or diagonal
            if (arr[j] == i || (Math.Abs(arr[j] - i) == Math.Abs(j - k)))
            {
                return false;
            }
        }
        return true;
    }

    // function to display the solution
    static void display(int n)
    {
        breakLine();
        Console.Write("Arrangement No. " + ++no);
        breakLine();

        for (int i = 1; i <= n; i++)
        {
            for (int j = 1; j <= n; j++)
            {
                // print '_' for empty cell and 'Q' for cell with queen
                if (arr[i] != j)
                {
                    Console.Write("\t_");
                }
                else
                {
                    Console.Write("\tQ");
                }
            }
            Console.WriteLine("");
        }

        breakLine();
    }

    // Driver code to initialize the problem and call the recursive function
    public static void Main(String[] args)
    {
        int n = 4; // size of the chessboard
        nQueens(1, n);
    }
}
