```
// Java code to find out minimum cost
// path to connect all the cities
import java.util.* ;

class GFG{

    // Function to find out minimum valued node
    // among the nodes which are not yet included in MST

    static int minNode(int n, int keyvals[], boolean mstset[])
    {
        int min_val = Integer.MAX_VALUE;
        int min_index = 0;

        // Loop through all the values of the nodes, 
        // which are not yet included in MST and find the minimum valued one.
        for(int i = 0; i < n; i++)
        {
            if (mstset[i] == false && keyvals[i] < min_val)
            {
                min_val = keyvals[i];
                min_index = i;
            }
        }
        return min_index;
    }

    // Function to find out the MST and
    // the cost of the MST.
    static void findCost(int n, int city[][])
    {

        // Array to store the parent nodes.
        int parent[] = new int[n];

        // Array to store the key value of each node.
        int keyvals[] = new int[n];

        // Boolean Array to indicate whether a node is included in MST or not.
        boolean mstset[] = new boolean[n];

        // Set all the key values to be infinite and none of the nodes is included in MST.
        for(int i = 0; i < n; i++)
        {
            keyvals[i] = Integer.MAX_VALUE;
            mstset[i] = false;
        }

        // Start to find the MST from node 0.
        // Parent of node 0 is none and set to be -1.
        // key value or minimum cost to reach 0th node from 0th node is 0.
        parent[0] = -1;
        keyvals[0] = 0;

        // Find the rest n-1 nodes of MST.
        for(int i = 0; i < n - 1; i++)
        {    
            // First find out the minimum node among the nodes which are not yet included in MST.
            int u = minNode(n, keyvals, mstset);

            // Include the uth node in MST.
            mstset[u] = true;

            // Update the values of neighbor nodes of u which are not yet included in MST.
            for(int v = 0; v < n; v++)
            {
                if (city[u][v] > 0 && mstset[v] == false && city[u][v] < keyvals[v])
                {
                    keyvals[v] = city[u][v];
                    parent[v] = u;
                }
            }
        }

        // Find out the cost by adding the edge values of MST.
        int cost = 0;
        for(int i = 1; i < n; i++)
            cost += city[parent[i]][i];

        System.out.println(cost);
    }

    // Driver code
    public static void main(String args[])
    {

        // Input 1
        int n1 = 5;
        int city1[][] = { { 0, 1, 2, 3, 4 },
                        { 1, 0, 5, 0, 7 },
                        { 2, 5, 0, 6, 0 },
                        { 3, 0, 6, 0, 0 },
                        { 4, 7, 0, 0, 0 } };

        findCost(n1, city1);

        // Input 2
        int n2 = 6;
        int city2[][] = { { 0, 1, 1, 100, 0, 0 },
                        { 1, 0, 1, 0, 0, 0 },
                        { 1, 1, 0, 0, 0, 0 },
                        { 100, 0, 0, 0, 2, 2 },
                        { 0, 0, 0, 2, 0, 2 },
                        { 0, 0, 0, 2, 2, 0 } };

        findCost(n2, city2);

    }
}
